section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-versioning.json",
  "type": "object",
  "title": "API versioning decision record",
  "required": [
    "spec_id",
    "decision",
    "rationale"
  ],
  "additionalProperties": false,
  "properties": {
    "spec_id": {
      "type": "string",
      "minLength": 1,
      "description": "Identifier of the spec under change (openapi file path)."
    },
    "decision": {
      "enum": [
        "additive",
        "create_v_next",
        "skip"
      ]
    },
    "from_version": {
      "type": "string",
      "pattern": "^v[0-9]+$"
    },
    "to_version": {
      "type": [
        "string",
        "null"
      ],
      "pattern": "^v[0-9]+$"
    },
    "deprecation_date": {
      "type": [
        "string",
        "null"
      ],
      "format": "date"
    },
    "sunset_date": {
      "type": [
        "string",
        "null"
      ],
      "format": "date"
    },
    "rationale": {
      "type": "string",
      "minLength": 10
    },
    "breaking_diff_ids": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "default": []
    }
  }
}
